from decimal import Decimal, InvalidOperation, ROUND_HALF_EVEN

def parse_monto(raw):
    t = str(raw).strip().replace(",", ".")
    try:
        return Decimal(t).quantize(Decimal("0.01"), rounding=ROUND_HALF_EVEN)
    except (InvalidOperation, ValueError) as e:
        raise ValueError(f"monto no parseable: {raw!r}") from e
print(parse_monto("12,5"))
try:
    parse_monto("abc")
except ValueError as e:
    print("err", e)

class DataLoadError(Exception):
    pass

def load_text(path_fn):
    try:
        return path_fn()
    except OSError as e:
        raise DataLoadError("no se pudo leer fuente") from e

def bad():
    raise FileNotFoundError("missing")
try:
    load_text(bad)
except DataLoadError as e:
    print(type(e).__name__, e.__cause__)

