def mask_email(e):
    local, _, domain = e.partition("@")
    if not domain:
        return "***"
    return (local[:1] + "***@" + domain) if local else "***@" + domain
def mask_phone(p):
    d = "".join(c for c in p if c.isdigit())
    return "***" + d[-3:] if len(d) >= 3 else "***"
