def process_batch(rows):
    clean, quarantine = [], []
    for r in rows:
        if "id" not in r or r["id"] is None:
            quarantine.append(r)
        else:
            clean.append(r)
    return {"n_clean": len(clean), "n_quarantine": len(quarantine), "clean": clean, "quarantine": quarantine}
