def retry_call(fn, max_attempts=3):
    last = None
    for i in range(max_attempts):
        try:
            return fn()
        except TimeoutError as e:
            last = e
            continue
    raise last
n = {"i": 0}
def flaky():
    n["i"] += 1
    if n["i"] < 3:
        raise TimeoutError("t")
    return "ok"
print(retry_call(flaky))
